+
+    private void useCaspianCSS() {
+        Application.setUserAgentStylesheet(Application.STYLESHEET_CASPIAN);
+    }
+
+    private void useModenaCSS() {
+        Application.setUserAgentStylesheet(Application.STYLESHEET_MODENA);
+    }
+
+    private static String stylesheet() {
+        // NOTE: the style names are used in RTAPropertySheet
+        String css =
+            """
+            .bold {
+                -fx-font-weight: bold;
+            }
+
+            .code {
+                -fx-font-family: Monospace;
+            }
+
+            .gray {
+                -fx-fill:gray;
+            }
+
+            .green {
+                -fx-fill:#3e8c25;
+            }
+
+            .italic {
+                -fx-font-family: serif;
+                -fx-font-style: italic;
+            }
+
+            .large {
+                -fx-font-size:200%;
+            }
+
+            .red {
+                -fx-fill:red;
+            }
+
+            .strikethrough {
+                -fx-strikethrough: true;
+            }
+
+            .monospaced {
+                -fx-font-family:Monospaced;
+            }
+
+            .underline {
+                -fx-underline: true;
+            }
+
+            .squiggly-css {
+                -fx-stroke-width: 0.6;
+                -fx-stroke: blue;
+            }
+
+            .highlight1 {
+                -fx-fill:red;
+            }
+
+            .highlight2 {
+                -fx-stroke-width:1;
+                -fx-stroke-fill:black;
+            }
+            """;
+        return "data:text/css;base64," + Base64.getEncoder().encodeToString(css.getBytes(StandardCharsets.US_ASCII));
+    }
+
+    private void print() {
+        Node n = contentPane.getCenter();
+        FX.print(n);
+    }

