+        Button cancel = new Button("Cancel");
+        cancel.setOnAction((_) -> {
+            onCompletion.run();
+        });
+        ButtonBar.setButtonData(cancel, ButtonData.CANCEL_CLOSE);
+        ButtonBar bb = new ButtonBar();
+        bb.getButtons().setAll(ok, cancel);
