+    private static int guessPlain(List<NamedValue<String>> styles) {
+        int sz = styles.size();
+        if (sz > 1) {
+            for (int i = 0; i < sz; i++) {
+                NamedValue<String> v = styles.get(i);
+                if (isPlain(v.getDisplay())) {
+                    return i;
+                }
+            }
+        }
+        return 0;
+    }
+
+    private static boolean isPlain(String style) {
+        switch(style.toLowerCase(Locale.ROOT)) {
+        case "regular":
+        case "plain":
+            return true;
+        }
+        return false;
+    }
