+        } else {
+            String name = f.getName();
+            String fam = f.getFamily();
+            double sz = f.getSize();
+
+            familyField.getSelectionModel().select(fam);
+            int ix = indexByValue(styleField.getItems(), name);
+            if (ix >= 0) {
+                styleField.getSelectionModel().select(ix);
+            }
+
+            ix = indexOf(sizeField.getItems(), sz);
